（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "c35896d564ed", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "905", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權與不動產法規", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00120', 'real-estate-appraiser', 'real-estate-appraiser-moex-109-9cd45b90', 'sub-real-estate-appraiser-06', NULL, 'essay', '甲在乙所有的土地設定地上權並僱工建築房屋一棟，惟因放樣失準，致
